 40	/* The first nibble of fs tells if it is High-G or not */
 41	static int lsm6dsv320x_accel_range_to_fs_val(const struct device *dev, int32_t range, uint8_t *fs)
 42	{
 43		switch (range) {
 44		case LSM6DSV320X_DT_FS_2G:
 45			*fs = 0;
 46			break;
 47	
 48		case LSM6DSV320X_DT_FS_4G:
 49			*fs = 1;
