 53			*fs = 2;
 54			break;
 55	
 56		case LSM6DSV320X_DT_FS_16G:
 57			*fs = 3;
 58			break;
 59	
 60		case LSM6DSV320X_DT_FS_32G:
 61			*fs = 4;
 62			break;
 63	
 64		case LSM6DSV320X_DT_FS_64G:
 65			*fs = 5;
 66			break;
