 68		case LSM6DSV320X_DT_FS_128G:
 69			*fs = 6;
 70			break;
 71	
 72		case LSM6DSV320X_DT_FS_256G:
 73			*fs = 7;
 74			break;
 75	
 76		case LSM6DSV320X_DT_FS_320G:
 77			*fs = 8;
 78			break;
 79	
 80		default:
