 87	static int lsm6dsv320x_accel_set_fs_raw(const struct device *dev, uint8_t fs)
 88	{
 89		const struct lsm6dsvxxx_config *cfg = dev->config;
 90		stmdev_ctx_t *ctx = (stmdev_ctx_t *)&cfg->ctx;
 91		struct lsm6dsvxxx_data *data = dev->data;
 92	
 93		if (lsm6dsv320x_is_std_fs(fs)) { /* 2g/4g/8g/16g */
 94			lsm6dsv320x_xl_full_scale_t val = fs;
 95	
 96			if (lsm6dsv320x_xl_full_scale_set(ctx, val) < 0) {
 97				return -EIO;
 98			}
 99	
100			data->out_xl = LSM6DSV320X_OUTX_L_A;
101		} else if (lsm6dsv320x_is_hg_fs(fs)) { /* 32g/64g/128g/256g/320g */
102			lsm6dsv320x_hg_xl_full_scale_t val = (fs - 4);
103	
104			if (lsm6dsv320x_hg_xl_full_scale_set(ctx, val) < 0) {
105				return -EIO;
106			}
107	
108			data->out_xl = LSM6DSV320X_UI_OUTX_L_A_OIS_HG;
109		} else {
110			return -EINVAL;
111		}
112	
113		data->accel_fs = fs;
114		data->acc_gain = lsm6dsv320x_accel_gain_ug(fs);
115	
116		return 0;
117	}
