177	static uint8_t lsm6dsv320x_freq_to_odr_val(const struct device *dev, int32_t freq)
178	{
179		const struct lsm6dsvxxx_config *cfg = dev->config;
180		stmdev_ctx_t *ctx = (stmdev_ctx_t *)&cfg->ctx;
181		lsm6dsv320x_data_rate_t odr;
182		int8_t mode;
183		size_t i;
184	
185		if (lsm6dsv320x_xl_data_rate_get(ctx, &odr) < 0) {
186			return -EINVAL;
187		}
188	
189		mode = (odr >> 4) & 0xf;
190	
191		for (i = 0; i < ARRAY_SIZE(lsm6dsv320x_odr_map[mode]); i++) {
192			if (freq <= lsm6dsv320x_odr_map[mode][i]) {
193				LOG_DBG("mode: %d - odr: %d", mode, i);
194				return i | (mode << 4);
195			}
196		}
197	
198		return 0xFF;
199	}
